record.field:
sequence, stay_tax_line = 0, False
for so_line in record.x_sale_order_id.order_line:
    if so_line.product_id.x_is_stay_tax: stay_tax_line = so_line
    sequence = max(sequence, so_line.sequence)
if stay_tax_line: stay_tax_line.write({'product_uom_qty': record.x_total, 'qty_delivered': record.x_total, 'sequence': 1 + sequence})
elif record.x_total > 0:
    product = env['product.product'].search([('x_is_stay_tax', '=', True)], limit=1)
    env['sale.order.line'].create({'order_id': record.x_sale_order_id.id, 'product_id': product.id, 'product_uom_qty': record.x_total, 'qty_delivered': record.x_total})

pickup_time = env.ref('sale_renting.recurrence_nightly').pickup_time
return_time = env.ref('sale_renting.recurrence_nightly').return_time
tz = env.ref('website.default_website').tz
for record in records:
    if not (record.role_id.x_is_a_room_offer and record.start_datetime and record.end_datetime): continue
    start_datetime = record.start_datetime.astimezone(tz=dateutil.tz.UTC)
    end_datetime = record.end_datetime.astimezone(tz=dateutil.tz.UTC)
    if record.start_datetime and str(record.start_datetime.time()) != f"{int(pickup_time):02d}:{int(pickup_time % 1 * 60):02d}:00":
        start = timezone(tz).localize(datetime.datetime(year=start_datetime.year, month=start_datetime.month, day=start_datetime.day, hour=int(pickup_time), minute=int(pickup_time % 1 * 60), second=0))
        start_datetime = start.astimezone(tz=dateutil.tz.UTC)
        if start_datetime >= end_datetime: start_datetime = start_datetime - datetime.timedelta(days=1)
    if record.end_datetime and str(record.end_datetime.time()) != f"{int(return_time):02d}:{int(return_time % 1 * 60):02d}:00":
        end = timezone(tz).localize(datetime.datetime(year=end_datetime.year, month=end_datetime.month, day=end_datetime.day, hour=int(return_time), minute=int(return_time % 1 * 60), second=0))
        end_datetime = end.astimezone(tz=dateutil.tz.UTC)
        if start_datetime >= end_datetime: end_datetime = end_datetime + datetime.timedelta(days=1)
    record['start_datetime'] = start_datetime.replace(tzinfo=None)
    record['end_datetime'] = end_datetime.replace(tzinfo=None)
for record in records:
    if not record.sale_line_id: continue
    nights = 0
    if record.sale_line_id.planning_slot_ids:
        nights = sum(record.sale_line_id.planning_slot_ids.mapped('x_nights'))
    record.sale_line_id.update({
        'start_date': record.start_datetime,
        'return_date': record.end_datetime,
        'x_nights': nights,
    })
    record.sale_line_id._reset_price_unit()

record.apply()
if record.order_id.rental_status == "returned" and any(line.product_id.x_has_city_tax for line in record.order_id.order_line):
    action = record.env['ir.actions.act_window']._for_xml_id('booking_engine.open_x_city_tax_action')
    action['context'] = {'search_default_x_sale_order_id': record.order_id.id, 'default_x_sale_order_id': record.order_id.id}

if slots := record.order_line.planning_slot_ids:
    for slot in slots.filtered(lambda s: s.resource_id.role_ids and any(role.x_is_a_room_offer for role in s.resource_id.role_ids)):
        slot.resource_id['x_occupancy'] = 'occupied'

if slots := record.order_line.planning_slot_ids:
    for slot in slots.filtered(lambda s: s.resource_id.role_ids and any(role.x_is_a_room_offer for role in s.resource_id.role_ids)):
        slot.resource_id['x_occupancy'] = 'vacant'

if (project := env['project.project'].search([('x_is_house_keeping_project', '=', True)], limit=1)):
    newtasks = []
    last_midnight = datetime.datetime.today().replace(hour=0, minute=0)
    for slot in env['planning.slot'].search([('start_datetime', '<', last_midnight),('end_datetime', '>', last_midnight)]):
        if any(role.x_is_a_room_offer for role in slot.resource_id.role_ids):
            end_today = slot.end_datetime < last_midnight + datetime.timedelta(hours=24)
            if (end_today and not slot.role_id.x_has_checkout_cleaning) or (not end_today and not slot.role_id.x_has_stayover_cleaning):
                continue
            slot.resource_id.write({'x_occupancy': 'due_out' if end_today else 'stayover'})
            newtasks.append({
                'name': "HK " + slot.resource_id.name,
                'project_id': project.id,
                'partner_id': slot.sale_line_id.order_id.partner_id.id,
                'description': "Automatically generated house keeping task.",
                'date_deadline': (last_midnight + datetime.timedelta(hours=24)),
                'x_resource_id': slot.resource_id.id,
                'x_cleaning': 'checkout' if end_today else 'stayover',
                'user_ids': [(5,0)],
            })
    env['project.task'].create(newtasks)

# This server action is called in a cron once a day and does 3 things: # 1. Archive the availabilities <= today # (it's not informative to see them and clutters the view) # 2. Create new ones at the start of the day # (so that we always have the right window of availabilities for Channex) # 3. Trigger a recomputation of all the availabilities # (to make sure we don't have a bugged/false state that does not reflect reality, # because unavoidable race conditions)
today, target_dates = datetime.date.today(), set(datetime.date.today() + datetime.timedelta(days=i) for i in range(500))
env['x_availability'].search([('x_date', '<', today), ('x_active', '=', True)]).write({'x_active': False})
if (offers := env['product.template'].search([('x_is_a_room_offer', '=', True)])):
existing_dates_by_offer = { offer.id: set(dates) for offer, dates in env['x_availability']._read_group( [('x_stay_offer_id', 'in', offers.ids), ('x_date', '>=', today), ('x_date', '<', today + datetime.timedelta(days=500))], ['x_stay_offer_id'], ['x_date:array_agg'] )}
# Create availabilities only for dates that don't exist to_create = [{'x_stay_offer_id': offer_id, 'x_date': d, 'x_to_recompute': True} for offer_id in offers.ids for d in (target_dates - existing_dates_by_offer.get(offer_id, set()))]
if to_create: env['x_availability'].create(to_create) # Recompute all availabilities (that are not archived) to make sure we have the correct information env['x_availability'].search([('x_date', '>=', today)]).write({'x_to_recompute': True})
env.ref('booking_engine.server_action_update_availabilities').run()
